export const meta = {
  name: 'decree-agentkith-research',
  description: 'Turn Agentkith dogfooding feedback into a grounded, cited decree improvement backlog',
  whenToUse: 'After collecting live dogfooding feedback, to decide what to actually build next in decree',
  phases: [
    { title: 'Ground', detail: 'agents read the decree codebase to establish current behavior + change surface per proposal' },
    { title: 'Search', detail: '5 web-research angles on how comparable tools solve the same problems' },
    { title: 'Verify', detail: 'adversarial 3-vote refutation of the load-bearing external claims' },
    { title: 'Synthesize', detail: 'merge internal reality + external precedent into a prioritized cited backlog' },
  ],
}

const OUT_PATH = '/private/tmp/claude-501/-Users-doruk-Desktop-SIDE-HUSTLE-decree/97e81602-5a57-4f68-807d-4f464be3f24b/scratchpad/decree-improvement-backlog.md'

// ---- Shared feedback context (distilled from docs/dogfooding-feedback/*) -------------------
const FEEDBACK = `
DECREE AGENTKITH DOGFOODING FEEDBACK (source: docs/dogfooding-feedback/).
Positive: decree's governs:/why/refs pushed the agent to fix the owning contract, not a local UI patch.
Core problem: \`intent-check\` mixes real blockers, corpus-hygiene debt, and expected multi-SPEC overlap into ONE exit-1 bucket. Goal is NOT fewer warnings ‚Äî it's TYPED warnings an agent can act on.

Evidence cases:
- Case1 (toolbar dictation): shared contract file returned NO governing decision from \`why\`; then a hot ViewModel was governed by 3 SPECs and intent-check exited 1 with no way to say "work under SPEC-X, treat the other 2 as contextual".
- Case2 (main composition root): overlap is structural/expected there; conflict output can't distinguish composition-root overlap from contradictory intent.
- Case3 (broad governance): two voice SPECs govern 66 and 60 paths, overlapping hot files; governs: became "files touched" not "files owned".
- Case4 (draft-but-shipped): SPEC at 100% primary ACs still status=draft; status stops signaling maturity.
- Case5 (SPEC self-edit): editing a decision doc triggered add_governance advice ‚Äî valid corpus maintenance looked ungoverned.

Proposed changes (NOT yet committed ‚Äî this workflow decides which to do & how):
- CI1 Add typed severity to intent-check: blocking_findings[] / advisory_findings[] / corpus_hygiene_findings[]. Keep exit codes 0/1/2 stable.
- CI2 Make --under SPEC-ID first-class: render report around the active decision (files owned, governs gaps, contextual overlaps, contradictions) instead of flat conflict list.
- CI3 Classify planned files: source_changes / corpus_changes / generated_artifact_changes; suppress add_governance for decree docs themselves.
- CI4 Broad-governance health signal (governs_count, hot_file_overlap_count, exact vs directory governs, governs_to_commits_ratio). Advisory only.
- CI5 Lifecycle-drift health signal (100% primary ACs + draft + commits attached; terminal status + changed ACs; implemented + stale governs gap).
- CI6 Human output: "block now" vs "clean later" sections + a recommended next command.
- CI7 Dogfood fixture suite built from the 5 Agentkith cases.
- SK1-6 Skill/agent-loop changes (decree-ddd): classify work mode (bugfix/feature/etc), name authoritative decision, prefer intent-check --under, don't blindly obey exit 1, boundary preflight for cross-layer work, final decree report contract.
Rollout plan (docs/dogfooding-feedback/05): P1 docs/skills, P2 intent-check output shape, P3 --under semantics, P4 health signals, P5 corpus-hygiene commands.
`.trim()

// ---- Schemas -------------------------------------------------------------------------------
const INTERNAL_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['area', 'current_behavior', 'items'],
  properties: {
    area: { type: 'string' },
    current_behavior: { type: 'string', description: 'What the relevant code/docs do TODAY, with file:line anchors' },
    key_files: { type: 'array', items: { type: 'string' } },
    items: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['feedback_ref', 'title', 'current_reality', 'change_surface', 'effort'],
        properties: {
          feedback_ref: { type: 'string', description: 'e.g. CI1, CI2, SK3' },
          title: { type: 'string' },
          current_reality: { type: 'string', description: 'Does this partly exist already? what exactly? file:line' },
          change_surface: { type: 'string', description: 'Concrete files/functions to change and how' },
          effort: { type: 'string', enum: ['S', 'M', 'L', 'XL'] },
          breaks_json_contract: { type: 'boolean' },
          risk: { type: 'string' },
          open_questions: { type: 'array', items: { type: 'string' } },
        },
      },
    },
  },
}

const EXTERNAL_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['angle', 'sources', 'claims'],
  properties: {
    angle: { type: 'string' },
    sources: { type: 'array', items: { type: 'object', additionalProperties: false, required: ['url', 'title'], properties: { url: { type: 'string' }, title: { type: 'string' } } } },
    claims: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['claim', 'source_url', 'maps_to'],
        properties: {
          claim: { type: 'string', description: 'A specific, falsifiable claim about how a real tool solves this' },
          source_url: { type: 'string' },
          maps_to: { type: 'string', description: 'Which decree proposal (CI1..CI7/SK) this informs and how' },
        },
      },
    },
  },
}

const VERDICT_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['verdict', 'reason'],
  properties: { verdict: { type: 'string', enum: ['supported', 'refuted', 'uncertain'] }, reason: { type: 'string' } },
}

// ---- Track 1: internal grounding over the decree codebase ----------------------------------
const INTERNAL = [
  {
    label: 'ground:intent-check',
    prompt: `You are grounding proposed changes against the REAL decree code. Read (Read/Grep) src/decree/commands/intent_check.py (~710 lines), its CLI wiring in src/decree/cli.py, docs/json-contracts.md, and the intent-check section of docs/usage.md and docs/llm-agent-integration.md.
Establish the CURRENT model: what finding types intent-check computes (conflict / stale governance / live-session overlap / missing governance), its exact exit codes, and its current JSON + human output shape (quote field names).
Then ground these proposals with concrete change surface + effort (S/M/L/XL) each:
- CI1 typed severity buckets blocking/advisory/corpus_hygiene (exit codes MUST stay 0/1/2). Where in the code are findings assembled? What would categorization touch? Does it break the JSON contract (breaks_json_contract)?
- CI2 make --under SPEC-ID first-class. Does --under ALREADY exist? If so what does it currently do vs. the proposed decision-relative report? If not, where to add it.
- CI3 classify planned files into source / corpus / generated-artifact, and suppress add_governance advice for decree document self-edits.
- CI6 split human output into "block now" vs "clean later" + a recommended next command.
Return per INTERNAL_SCHEMA. Be specific with file:line anchors; do not speculate about code you did not read.`,
  },
  {
    label: 'ground:health',
    prompt: `Ground proposed HEALTH signals against real code. Read src/decree/commands/health.py (~716 lines), docs/health-signals.md, and how the drift/staleness model works (grep for stale, drift, governs, commits). Note that CLAUDE.md says "Staleness is direct-only, not transitive".
Establish current health signals + their output. Then ground:
- CI4 broad-governance advisory signal: governs_count, hot_file_overlap_count, exact-path vs directory governs, governs_to_commits_ratio. Which of these metrics are already computable from existing data? Where is governs: parsed and where are commits derived?
- CI5 lifecycle-drift signal: (a) 100% primary ACs + status=draft + commits attached; (b) terminal status + ACs changed after report snapshot; (c) implemented + stale governs gap. Does health already know progress% and status? Where?
Give concrete change surface + effort each. Return per INTERNAL_SCHEMA.`,
  },
  {
    label: 'ground:governance-model',
    prompt: `Ground the DATA model that CI3/CI4/CI5 depend on. Find and read the code for: \`decree why\`, \`decree refs\`, the governs: parser, \`decree progress\`, and \`decree status\` (grep src/decree for governs, why, refs, progress, status; parser.py holds DocFrontmatter/DocDocument).
Answer: How is governs: stored per document and inverted into path->decisions? How does why/refs compute? How is progress% (primary ACs) computed and where does the report snapshot live? How is a "hot file" (governed by many decisions) detectable today? How would we distinguish exact-path governs vs directory/glob governs? What data already exists to separate a "file owned by decision" from "file merely touched"?
This is a data-availability audit for CI3 (source/corpus/generated classification), CI4 (broad-governance metrics), CI5 (status/progress drift). Return per INTERNAL_SCHEMA with area="governance-data-model"; items should be data/capability gaps with effort.`,
  },
  {
    label: 'ground:skills-agent-loop',
    prompt: `Ground the SKILL / agent-loop changes. Read src/decree/templates/agent/skills/decree-ddd/SKILL.md, other files under src/decree/templates/agent/skills/ and top-level skills/, plus docs/llm-agent-integration.md and AGENTS.md. Also check the decree MCP server surface in src/decree/commands/mcp_server.py (which tools it exposes to agents).
Establish the CURRENT recommended agent loop (what the skill tells an LLM to do around lint/progress/why/intent-check). Then ground SK1-6:
- classify work mode (bugfix/feature/architecture/refactor/corpus/release) before intent-check
- force naming an authoritative decision and prefer intent-check --under
- interpret exit-1 by severity instead of blindly resolving all findings first
- boundary preflight for cross-layer work
- "update the SPEC before code" guidance
- final decree report contract (active decision / findings by bucket / governance changes / residual drift)
Which of these are pure prompt/doc edits (P1, low risk) vs. which depend on core changes (CI1 severity, CI2 --under) landing first? Return per INTERNAL_SCHEMA with area="skills-agent-loop".`,
  },
  {
    label: 'ground:contracts-and-fixtures',
    prompt: `Ground the CONTRACT-SAFETY and TESTING work. Read docs/json-contracts.md fully, src/decree/config.py (~275 lines), and survey tests/ (how intent-check/health are tested; are there fixture corpora? grep tests for intent_check, health, fixture, tmp_path, and any conftest).
Answer: What is decree's stated JSON contract stability policy (additive vs breaking, versioning)? How can CI1's new blocking/advisory/corpus_hygiene fields be added additively without breaking existing --json consumers?
Then ground CI7: design the dogfood fixture suite from the 5 Agentkith cases (hot ViewModel governed by 3 complementary SPECs; shared contract initially ungoverned then governed under the active SPEC; a planned SPEC self-edit; a draft-at-100% SPEC; a broad-governs SPEC with 60+ paths). What fixture format do existing tests use, and what's the effort to build these? Return per INTERNAL_SCHEMA with area="contracts-and-fixtures".`,
  },
]

// ---- Track 2: external research angles ------------------------------------------------------
const EXTERNAL = [
  {
    label: 'search:severity-taxonomies',
    angle: 'How code-analysis tools type findings by severity so consumers can gate blocking vs advisory',
    prompt: `Research how established code-analysis / policy tools classify findings by SEVERITY so downstream consumers can fail-closed on some and treat others as advisory. Use WebSearch then WebFetch the best sources. Cover: SARIF result "level" (error/warning/note) and "kind"; ESLint error/warn/off and how CI gates on error only; Semgrep severity (ERROR/WARNING/INFO) and blocking config; OPA/conftest deny vs warn; RuboCop/Rubocop severities.
Extract falsifiable claims about the exact taxonomy and how it's consumed. This informs decree CI1 (blocking_findings/advisory_findings/corpus_hygiene_findings while keeping a stable exit code). Return per EXTERNAL_SCHEMA. Prefer official docs/specs over blog posts.`,
  },
  {
    label: 'search:baseline-new-vs-debt',
    angle: 'Separating NEW findings (this change) from pre-existing debt (baseline/ratchet) ‚Äî maps to blocking vs corpus-hygiene',
    prompt: `Research how tools separate NEW findings introduced by the current change from PRE-EXISTING debt, so they only block on the new ones. Use WebSearch + WebFetch. Cover: SARIF baselining / "baselineState" (new/unchanged/updated/absent); Semgrep --baseline-commit; git-diff-scoped linting; the "baseline"/"ratchet" pattern (e.g. betterer, tslint/eslint baselines, danger.js); PR-scoped vs repo-scoped analysis.
This directly informs decree's blocking (current plan) vs corpus_hygiene (pre-existing debt) split and the "--changed" / diff-scoped idea. Extract falsifiable claims. Return per EXTERNAL_SCHEMA.`,
  },
  {
    label: 'search:ownership-overlap',
    angle: 'Representing a file owned by MULTIPLE domains/owners without calling it a conflict',
    prompt: `Research how ownership/governance systems represent a file that legitimately belongs to MULTIPLE owners/domains without treating overlap as an error. Use WebSearch + WebFetch. Cover: GitHub CODEOWNERS semantics (last-matching-pattern wins, multiple owners, precedence); Backstage catalog ownership + system/domain modeling; Bazel/monorepo visibility & layering; "bounded context"/composition-root patterns where a wiring file touches many domains.
This informs decree CI2/Case2: distinguishing contextual overlap and composition-root overlap from a real semantic conflict when 3 SPECs govern one hot file. Extract falsifiable claims. Return per EXTERNAL_SCHEMA.`,
  },
  {
    label: 'search:adr-lifecycle',
    angle: 'ADR/decision lifecycle & status enforcement, superseded/drift handling',
    prompt: `Research ADR / decision-record LIFECYCLE and status enforcement. Use WebSearch + WebFetch. Cover: MADR status values (proposed/accepted/deprecated/superseded) and superseded-by links; log4brains lifecycle & status handling; adr-tools supersede workflow; how projects detect drift between an "accepted" record and shipped code; any tooling that flags stale/complete-but-not-accepted decisions.
This informs decree CI5 (a SPEC at 100% ACs still status=draft; terminal-status drift) and the warn_on_reference/terminal-status model. Extract falsifiable claims about real conventions, not opinions. Return per EXTERNAL_SCHEMA.`,
  },
  {
    label: 'search:agent-facing-output',
    angle: 'Designing tool output that LLM agents interpret rather than obey blindly',
    prompt: `Research how to design command/tool output and exit-code conventions for AUTONOMOUS LLM AGENTS so they interpret findings rather than blindly obey a nonzero exit. Use WebSearch + WebFetch. Cover: guidance on machine-readable structured output for agents, severity/actionability signals, "advisory vs blocking" in agent tool design, exit-code conventions consumed by agent loops, and any writing on agents over-reacting to lint/CI failures. Also relevant: how MCP tool results / structured content are designed for agent consumption.
This informs decree SK1-6 (agent loop must interpret exit 1 by severity) and CI6. Extract falsifiable claims. Prefer authoritative sources (Anthropic/OpenAI/vendor docs, well-known engineering writeups). Return per EXTERNAL_SCHEMA.`,
  },
]

// ---- Helpers --------------------------------------------------------------------------------
function dedupeClaims(items) {
  const seen = new Set()
  const out = []
  for (const it of items) {
    const k = (it.claim || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().slice(0, 90)
    if (!k || seen.has(k)) continue
    seen.add(k)
    out.push(it)
  }
  return out
}

// ---- Run ------------------------------------------------------------------------------------
phase('Ground')
log('Track 1: grounding proposals in the decree codebase ¬∑ Track 2: researching external precedent')

const [internal, external] = await Promise.all([
  parallel(INTERNAL.map((a) => () => agent(a.prompt + '\n\nCONTEXT:\n' + FEEDBACK, { label: a.label, phase: 'Ground', schema: INTERNAL_SCHEMA }))),
  parallel(EXTERNAL.map((a) => () => agent(a.prompt, { label: a.label, phase: 'Search', schema: EXTERNAL_SCHEMA }))),
])

const internalOk = internal.filter(Boolean)
const externalOk = external.filter(Boolean)

// Collect top ~3 claims per angle, dedupe, cap 12 for verification.
const rawClaims = externalOk.flatMap((e) => (e.claims || []).slice(0, 3).map((c) => ({ ...c, angle: e.angle })))
const claims = dedupeClaims(rawClaims).slice(0, 12)
log(`Collected ${rawClaims.length} claims from ${externalOk.length}/5 angles; verifying ${claims.length} after dedupe`)

phase('Verify')
const verifiedRaw = await parallel(
  claims.map((c, i) => () =>
    parallel(
      [1, 2, 3].map((v) => () =>
        agent(
          `Adversarially REFUTE this claim about how a real tool works. Try hard to find it wrong, out-of-date, or misattributed. Default to "refuted" or "uncertain" if you cannot independently confirm it. Use WebSearch/WebFetch if useful.\n\nCLAIM: ${c.claim}\nCITED SOURCE: ${c.source_url}\nCLAIMED RELEVANCE TO DECREE: ${c.maps_to}`,
          { label: `verify:${i}:${v}`, phase: 'Verify', schema: VERDICT_SCHEMA },
        ),
      ),
    ).then((votes) => {
      const v = votes.filter(Boolean)
      const refutes = v.filter((x) => x.verdict === 'refuted').length
      return { claim: c, survived: refutes < 2, refutes, votes: v }
    }),
  ),
)
const survivors = verifiedRaw.filter(Boolean).filter((r) => r.survived).map((r) => r.claim)
const killed = verifiedRaw.filter(Boolean).filter((r) => !r.survived).length
log(`Verification: ${survivors.length} claims survived, ${killed} refuted`)

// ---- Synthesis (draft -> critic -> final) ---------------------------------------------------
phase('Synthesize')

const internalBlob = JSON.stringify(internalOk, null, 1)
const claimsBlob = survivors.map((c, i) => `[S${i + 1}] ${c.claim}  (maps_to: ${c.maps_to})  <${c.source_url}>`).join('\n')

const STRUCTURE = `Produce a DECREE IMPROVEMENT BACKLOG in Markdown with these sections:
1. "## TL;DR" ‚Äî 4-6 sentences: the core direction (typed findings, not fewer findings) and the top 3 things to build first.
2. "## Prioritized backlog" ‚Äî a table: | ID | Change | Feedback ref | Current code reality (does it partly exist?) | Effort | Impact | Risk | Doc type (PRD/ADR/SPEC/skill-edit) | Rollout phase |. One row per actionable item (CI1..CI7, SK cluster, plus any gap you infer). Rank most-valuable-first.
3. "## Item detail" ‚Äî one subsection per backlog item: what to change (with file:line anchors from the grounding), why (tie to an Agentkith case), external precedent with citations like [S3], and open questions.
4. "## Sequencing" ‚Äî quick wins (pure doc/skill, no code) vs. needs-a-decision (write an ADR first) vs. bigger builds. Map to the 5-phase rollout in docs/dogfooding-feedback/05.
5. "## Decisions to make" ‚Äî the open questions a human must answer before building (e.g. does --under already exist? should corpus classification be config-driven?).
6. "## Sources" ‚Äî numbered list of the surviving external claims' URLs.
Rules: be concrete and honest about what already exists vs. is new (use the grounding). Do NOT invent file paths. Cite external precedent only from the SURVIVING claims below. Keep it actionable ‚Äî this is a build plan, not an essay.`

const draft = await agent(
  `You are synthesizing a research report that decides what to build next in decree (a decision-lifecycle CLI: PRD/ADR/SPEC + governs:/why/refs/intent-check/health).\n\n${FEEDBACK}\n\nINTERNAL GROUNDING (current code reality + change surface, JSON):\n${internalBlob}\n\nSURVIVING EXTERNAL CLAIMS (adversarially verified; cite as [S#]):\n${claimsBlob || '(none survived ‚Äî rely on internal grounding and note the gap)'}\n\n${STRUCTURE}`,
  { label: 'synthesize:draft', phase: 'Synthesize' },
)

const critique = await agent(
  `Critique this draft decree backlog for a demanding staff engineer. Find: (a) any of the feedback items CI1-CI7 or SK1-6 that are missing from the backlog; (b) any claim about current decree behavior that the grounding does NOT support or contradicts; (c) priorities that seem wrong given effort vs impact; (d) missing dependencies (e.g. a skill change that secretly needs a core change first); (e) missing citations. Be specific and terse ‚Äî a bullet list of concrete fixes.\n\nGROUNDING (ground truth):\n${internalBlob}\n\nDRAFT:\n${draft}`,
  { label: 'synthesize:critic', phase: 'Synthesize' },
)

const final = await agent(
  `Revise the backlog to fix every valid point in the critique. Keep the exact section structure. Then use the Write tool to save the final Markdown to this exact path: ${OUT_PATH}\nAfter writing, return the FULL final Markdown as your response text (not a summary).\n\n${STRUCTURE}\n\nDRAFT:\n${draft}\n\nCRITIQUE TO ADDRESS:\n${critique}\n\nSURVIVING EXTERNAL CLAIMS (for citations):\n${claimsBlob}`,
  { label: 'synthesize:final', phase: 'Synthesize' },
)

return {
  outPath: OUT_PATH,
  internalAreas: internalOk.length,
  claimsVerified: survivors.length,
  claimsRefuted: killed,
  report: final,
}

